export const CATEGORIES = [
  {
    name: 'Electrical',
    solutions: [
      { title: 'Power Failure', steps: '1. Check if the main circuit breaker has tripped.\n2. Inspect the local switchboard for any tripped switches.\n3. Verify if other rooms/areas are also without power (to determine if it is a local or campus-wide issue).\n4. Do not attempt to reset a tripped breaker without authorization.\n5. Call the campus electrician immediately.\n6. Do not use candles or open flames as alternatives.\n7. Unplug sensitive equipment (computers, projectors) to avoid damage when power returns.\n8. Report the exact location (building, floor, room number) to the helpdesk.\n9. If it is an emergency situation, call campus security.\n10. Wait for the authorized electrician to diagnose and restore power.' },
      { title: 'Faulty Switch Not Working', steps: '1. Check if the switch is receiving power (test nearby sockets).\n2. Do not repeatedly flick a sparking or burning switch.\n3. Do not attempt to open or repair the switch yourself.\n4. Mark the switch with a "Do Not Use" label to warn others.\n5. Report the exact room and switch location to the helpdesk.\n6. The electrician will test for wiring issues behind the switch.\n7. If the switch makes a buzzing noise, vacate the room as a precaution.\n8. Do not pour water near a faulty electrical switch.\n9. Await the electrician confirmation before using any alternative switches on the same line.\n10. Follow up with the helpdesk if not attended to within 24 hours.' },
      { title: 'Light Not Working', steps: '1. Check if the bulb has fused — it may simply need replacement.\n2. Check if the wall switch for that light is turned on.\n3. Test other lights in the same room to isolate the fault.\n4. If all lights in the room are out, it may be a circuit breaker issue.\n5. Report to the helpdesk with the room number and which light fixture is affected.\n6. Do not climb ladders or chairs to replace bulbs — request maintenance staff.\n7. If the fitting is flickering, do not use it — report it as a fire hazard.\n8. The electrician will check the fitting, bulb, and wiring.\n9. Ensure the area is adequately lit using torch/other lights until fixed.\n10. Confirm the issue is resolved and close the ticket after the repair.' },
      { title: 'Exposed Wires Found', steps: '1. IMMEDIATELY stop using the area near the exposed wire.\n2. Do not touch the wire under any circumstances.\n3. Warn anyone nearby to stay away.\n4. Switch off the electricity at the local switchboard if safe to do so.\n5. Place a visible warning sign or barrier around the area.\n6. Call campus security and the electrician IMMEDIATELY — this is a critical hazard.\n7. Submit an emergency ticket to the helpdesk marked URGENT/High priority.\n8. Take a photo of the exposed wire for documentation (without touching it).\n9. Do not allow students or staff to enter the area until it is repaired.\n10. Await confirmation from the electrician that the area is safe to re-enter.' },
      { title: 'Short Circuit / Tripped Breaker', steps: '1. Identify if a specific breaker in the distribution board has tripped (it will be in the middle position).\n2. Switch off all equipment connected to that circuit.\n3. Do not reset the breaker yourself — call the electrician.\n4. Report the location of the distribution board and affected area.\n5. The electrician will identify the cause (overload, faulty device, moisture).\n6. One appliance at a time will be reconnected after the circuit is checked.\n7. Identify and remove the faulty appliance from the circuit.\n8. The breaker is reset only after the fault is cleared.\n9. Consider redistributing high-load appliances across different circuits.\n10. Submit a ticket for regular inspection if tripping is recurring.' },
      { title: 'Electrical Sparks from Socket', steps: '1. Do not touch the socket or insert any plug into it.\n2. Switch off the power to that socket from the switchboard.\n3. Tape over the socket with insulation tape and label it "Faulty — Do Not Use".\n4. Clear the surrounding area and submit an URGENT helpdesk ticket.\n5. Call campus security for assistance in case of fire risk.\n6. The electrician will inspect the socket, wiring, and connection terminals.\n7. Do not use extension cords connected to that circuit until inspected.\n8. Take photos for documentation and the incident report.\n9. Keep a fire extinguisher (CO2 type) nearby as a precaution.\n10. Only begin using the socket again after written clearance from the electrician.' },
      { title: 'Electric Shock Received', steps: '1. Do not touch the person if they are still in contact with the power source.\n2. Switch off the power at the main switch or breaker immediately.\n3. Call campus emergency services / ambulance without delay.\n4. Check if the person is conscious and breathing.\n5. Administer first aid / CPR only if trained to do so.\n6. Do not move the person unnecessarily if spinal injury is suspected.\n7. Contact campus security and the administration office.\n8. The affected electrical equipment must not be used until inspected.\n9. File an incident report with the helpdesk and administration.\n10. A full investigation must be carried out to prevent recurrence.' },
      { title: 'Street / Campus Outdoor Lights Not Working', steps: '1. Note the exact location of the non-functional light (post number or landmark).\n2. Check if multiple nearby lights are also out (could be a feeder circuit issue).\n3. Report to the helpdesk with location details and time of observed failure.\n4. Campus security should be alerted as dark areas are a safety concern.\n5. The electrician will check the outdoor light fitting, driver, and circuit.\n6. If the pole is leaning or damaged, treat it as an emergency.\n7. Do not loiter near damaged outdoor electrical poles.\n8. Temporary lighting may be deployed by the maintenance team if repair is delayed.\n9. Follow up with the helpdesk if not repaired before the next evening.\n10. Ensure the repair is documented and the ticket is closed upon completion.' },
      { title: 'Generator / UPS Not Starting', steps: '1. Check if the generator has fuel — this is the most common reason.\n2. Check the battery of the generator/UPS for charge.\n3. Check if the generator auto-start switch is in "Auto" mode.\n4. Look at the generator control panel for any fault codes or alarms.\n5. Do not attempt to manually start a generator that has a fault alarm active.\n6. Report to the helpdesk and electrician with the fault code displayed.\n7. Do not overload the generator — remove non-critical loads.\n8. The UPS battery may need replacement if it no longer holds charge.\n9. Schedule a full monthly maintenance check for the generator.\n10. Ensure the generator room is ventilated and free from obstructions.' },
      { title: 'Overloaded Power Sockets / Extension Boards', steps: '1. Immediately reduce the number of devices plugged into the socket or extension board.\n2. Never plug one extension board into another (daisy-chaining).\n3. Check if the socket/board is warm to the touch — if so, switch it off immediately.\n4. High-power devices (ACs, heaters) must have dedicated sockets.\n5. Report to facilities if more sockets are needed in a room.\n6. The electrician will assess if additional circuits need to be installed.\n7. Use only ISI-marked quality extension boards with surge protectors.\n8. Switch off extension boards when not in use.\n9. Educate lab/classroom users on safe power usage practices.\n10. Submit a ticket for additional power socket installation if needed.' },
      { title: 'Fluorescent Tube Flickering', steps: '1. Check if the flickering is constant or intermittent.\n2. Do not stare directly at flickering lights as they may cause headaches or seizures.\n3. Turn off the light switch and wait 5 minutes before turning it back on.\n4. If flickering persists, report to helpdesk immediately.\n5. Note down which specific tubes in the fixture are flickering.\n6. The electrician will check the ballast and starter.\n7. Faulty ballasts will be replaced with LED-compatible ones.\n8. Old fluorescent tubes may need replacement with LED alternatives.\n9. Ensure proper earthing of the light fixture.\n10. Schedule regular maintenance for all classroom lighting fixtures.' },
      { title: 'Electrical Panel Door Open/Unlocked', steps: '1. Do not touch any switches or components inside the panel.\n2. Keep people away from the open electrical panel.\n3. Check if the panel key is nearby or if the lock is broken.\n4. Report to campus security and electrician immediately.\n5. The panel door should be closed and locked for safety.\n6. Only authorized electricians should access electrical panels.\n7. Install tamper-proof locks if panels are being accessed by unauthorized persons.\n8. Schedule regular checks to ensure all electrical panels are secure.\n9. Post warning signs near electrical panels if they are in public areas.\n10. Conduct safety training for staff on electrical panel security.' },
      { title: 'Extension Cord Running Across Walkways', steps: '1. Immediately create a safe path around the extension cord.\n2. Place warning signs or tape to alert people of the tripping hazard.\n3. Do not move the extension cord if it is powering critical equipment.\n4. Report the hazard to facilities management immediately.\n5. Request installation of permanent electrical outlets where needed.\n6. Use cord protectors or ramps for temporary installations.\n7. Ensure cords are routed along walls or under furniture when possible.\n8. Check if wireless alternatives can replace wired equipment.\n9. Schedule periodic inspections for electrical safety hazards.\n10. Implement policies restricting extension cord use across pedestrian areas.' },
      { title: 'Ceiling Fan Making Noise', steps: '1. Turn off the ceiling fan immediately to prevent further damage.\n2. Check if the fan is wobbling or shaking excessively.\n3. Look for any loose screws or mounting hardware from below.\n4. Do not attempt to climb and fix the fan yourself.\n5. Report to maintenance with details about the type of noise (grinding, clicking, etc.).\n6. The electrician will inspect fan motor bearings and balance.\n7. Fan blades may need realignment or replacement.\n8. Loose mounting bolts will be tightened or replaced.\n9. Old fans may need complete replacement for safety.\n10. Schedule annual maintenance for all ceiling fans in campus.' },
      { title: 'Power Surge Damage to Equipment', steps: '1. Immediately unplug all affected electronic equipment.\n2. Do not attempt to turn on damaged equipment.\n3. Check if multiple devices were affected simultaneously.\n4. Report to IT department and facilities management.\n5. Document all damaged equipment with photos and serial numbers.\n6. Check if surge protectors were in use and if they need replacement.\n7. The electrician will inspect the main electrical supply for voltage irregularities.\n8. Install whole-building surge protection if not already present.\n9. File insurance claims for damaged equipment if applicable.\n10. Implement policy requiring surge protection for all sensitive equipment.' },
    ],
  },
  {
    name: 'Network / Internet',
    solutions: [
      { title: 'WiFi Not Working', steps: '1. Check if the WiFi indicator light on the access point / router is green.\n2. Disconnect and reconnect to the campus WiFi network.\n3. Forget the network on your device and reconnect with credentials.\n4. Try connecting with another device to confirm if it is a device issue.\n5. Check if your device\'s WiFi adapter is turned on (not in airplane mode).\n6. Restart your device and attempt to reconnect.\n7. Report to the helpdesk with the specific location (room, floor, block) and time.\n8. The network team will check the access point for that area.\n9. A replacement access point may be deployed if the current one is faulty.\n10. Follow up if the issue persists after the team has investigated.' },
      { title: 'LAN Cable Damage', steps: '1. Visually inspect the LAN cable for cuts, kinks, or broken connectors.\n2. Try a different LAN cable to confirm if the cable is the issue.\n3. Check if the LAN port on the device and the wall socket are functioning.\n4. Report the damaged cable location and port number to the helpdesk.\n5. Do not attempt to splice or repair a LAN cable yourself.\n6. The network team will replace the cable with a tested, certified one.\n7. Ensure cables are not run under doors or across walkways.\n8. If a wall socket is damaged, an electrician may need to inspect it.\n9. Properly route and organize cables to avoid future damage.\n10. Use cable protectors/raceways in high-traffic areas to prevent damage.' },
      { title: 'Router / Switch Malfunction', steps: '1. Check all indicator lights on the router/switch (power, link, port status).\n2. Power cycle the router/switch by unplugging for 30 seconds.\n3. Check if connected devices lose connectivity simultaneously.\n4. Report to the helpdesk with the device location and model if visible.\n5. The network team will remotely check device status and logs.\n6. A config reset may be performed if the device has frozen.\n7. A replacement device will be deployed if hardware failure is confirmed.\n8. Connected devices will need to reconnect after the replacement.\n9. Core switches will have a spare unit for hot-swap in critical labs.\n10. A network topology review may be done to prevent single points of failure.' },
      { title: 'Slow Internet Speed', steps: '1. Run a speed test at speedtest.net or fast.com and note the result.\n2. Check how many users are connected — bandwidth may be congested.\n3. Avoid video streaming on educational networks during class hours.\n4. Check if a background update or download is consuming bandwidth.\n5. Move closer to the WiFi access point or use a wired connection.\n6. Report slow speeds to the helpdesk with the test results and location.\n7. The network team will check the uplink capacity and bandwidth usage.\n8. Download this from the internet or cloud storage during off-peak hours.\n9. Quality of Service (QoS) rules may be applied to prioritize traffic.\n10. ISP capacity may need to be upgraded if demand consistently exceeds bandwidth.' },
      { title: 'Cannot Connect to Campus Portal / Internal System', steps: '1. Check if the portal was accessible recently or has been down for a while.\n2. Try accessing the portal from a different browser or device.\n3. Clear the browser cache and cookies, then retry.\n4. Ensure you are connected to the campus network (not mobile data).\n5. Disable VPN if active, as it may route traffic incorrectly.\n6. Check the campus IT status page for any announced maintenance.\n7. Report to the helpdesk with the portal URL and the error message.\n8. The IT team will check the web server and DNS resolution.\n9. A server restart or patch may be required.\n10. You will be notified via email when the portal is restored.' },
      { title: 'IP Address Conflict on Campus Network', steps: '1. The affected device will show a "Network Address Conflict" warning.\n2. Open a command prompt and run `ipconfig /release` then `ipconfig /renew`.\n3. If using a static IP, change it or revert to DHCP (automatic).\n4. Report to the network administrator with the device MAC address.\n5. The admin will check the DHCP allocation table for conflicts.\n6. Reserved IPs should be assigned for devices needing static addresses.\n7. The network team will clear the conflicting entry from the DHCP server.\n8. All campus devices should generally use DHCP.\n9. Unauthorized static IP assignment by users is not permitted.\n10. The network team will review DHCP pool size if conflicts are frequent.' },
      { title: 'Network Port Not Active (Wired)', steps: '1. Check if the LAN cable is securely plugged into both the device and wall socket.\n2. Try a different cable to eliminate cable fault.\n3. Check the link light on the Network Interface Card (NIC).\n4. Try the cable in a different network port/socket nearby if available.\n5. Report the wall socket number (usually labelled) and location to the helpdesk.\n6. The network team will check if the port is active/patched in the network room.\n7. The port may need to be patched to the active switch port.\n8. VLAN assignment may need to be corrected for that port.\n9. The network team will test end-to-end connectivity.\n10. The port will be activated and tested before closing the ticket.' },
      { title: 'Cannot Print on Campus Network Printer', steps: '1. Check if the printer is powered on and online (no error lights).\n2. Ensure you are on the correct campus network (not a guest VLAN).\n3. Re-add the printer using its IP address rather than hostname.\n4. Clear the print queue and retry.\n5. Restart the Print Spooler service on your PC.\n6. Check if other users can print to the same printer.\n7. Report to the helpdesk with the printer name/location and your device details.\n8. The network team will check IP reachability to the printer.\n9. Driver reinstallation may be needed on the reporting device.\n10. A dedicated print server port may need to be verified if the printer is networked.' },
      { title: 'Campus WiFi Password Not Working', steps: '1. Confirm you are entering the correct SSID and password (case-sensitive).\n2. Forget the network and reconnect manually.\n3. Check if your device date/time is correct (affects authentication).\n4. Try connecting on another device to confirm if your credentials are valid.\n5. Contact the helpdesk to verify your network access account is active.\n6. New students/staff may not yet have their account provisioned.\n7. The network admin will confirm your credentials in the RADIUS/AAA system.\n8. A temporary password reset may be issued.\n9. MAC-based filtering may need to be updated for your device.\n10. You will receive new credentials via your campus email.' },
      { title: 'High Network Latency / Packet Loss', steps: '1. Open command prompt and run `ping 8.8.8.8 -n 20` to check packet loss.\n2. Note the average latency and percentage of lost packets.\n3. Check if other users in the area experience the same issue.\n4. Switch to a wired connection and compare results.\n5. Report to the helpdesk with ping results and your location.\n6. The network team will trace the route to identify where loss occurs.\n7. A faulty switch port or cable may be causing errors.\n8. WAN link utilization will be checked — congestion may be the cause.\n9. QoS may be adjusted to prioritize real-time traffic.\n10. If ISP-level packet loss is confirmed, a fault will be raised with the ISP.' },
      { title: 'VPN Connection Issues', steps: '1. Check if you are using the approved campus VPN client.\n2. Verify your VPN credentials are correct and not expired.\n3. Try connecting to different VPN server locations.\n4. Disable other VPNs or proxy connections that might conflict.\n5. Check if your device firewall is blocking VPN traffic.\n6. Try switching between different VPN protocols (OpenVPN, IKEv2, etc.).\n7. Report to IT support with error messages and connection logs.\n8. The network team will check VPN server capacity and configuration.\n9. Update VPN client software to the latest version.\n10. Test VPN connection from different network locations to isolate the issue.' },
      { title: 'Email Server Connection Problems', steps: '1. Check if you can access webmail through your browser.\n2. Verify your email client settings (SMTP, IMAP, ports).\n3. Try sending/receiving emails from webmail to test server status.\n4. Check if your device firewall is blocking email ports.\n5. Verify your email account credentials and password.\n6. Report to IT with specific error messages from your email client.\n7. The server team will check mail server status and logs.\n8. Update your email client to the latest version.\n9. Check campus network status page for known email issues.\n10. Test with different email clients to isolate client-specific issues.' },
      { title: 'DNS Resolution Problems', steps: '1. Try accessing websites by IP address instead of domain names.\n2. Flush your DNS cache: run `ipconfig /flushdns` on Windows.\n3. Try using different DNS servers (8.8.8.8, 1.1.1.1) temporarily.\n4. Check if the issue affects all devices or just yours.\n5. Restart your network adapter or reconnect to WiFi.\n6. Report to network team with specific websites that are unreachable.\n7. The team will check campus DNS server configuration.\n8. Test nslookup commands to identify DNS server response.\n9. Check if parental controls or content filters are blocking domains.\n10. Verify network time synchronization as it can affect DNS resolution.' },
      { title: 'Firewall Blocking Campus Services', steps: '1. Identify which specific service or application is being blocked.\n2. Check if you are using the correct ports and protocols.\n3. Temporarily disable local firewall to test connectivity.\n4. Check Windows Defender or antivirus software settings.\n5. Try accessing the service from a different device or network.\n6. Report to network team with details of blocked service.\n7. The team will review firewall rules and exceptions.\n8. Request addition of necessary ports to allowed list.\n9. Check if the service requires VPN access for security.\n10. Document approved services and their required ports for future reference.' },
      { title: 'Wireless Access Point Overheating', steps: '1. Check if the wireless access point feels excessively hot.\n2. Ensure adequate ventilation around the access point.\n3. Check if any vents on the device are blocked by dust or debris.\n4. Look for warning lights or status indicators on the device.\n5. Check network performance in the area - overheating can cause slowdowns.\n6. Report the location and model of the overheating access point.\n7. The network team will inspect the device and cooling system.\n8. Professional cleaning may be required to remove dust buildup.\n9. Replacement may be necessary if cooling system has failed.\n10. Schedule regular maintenance and cleaning for all network equipment.' },
    ],
  },
  {
    name: 'Plumbing',
    solutions: [
      { title: 'Water Leakage', steps: '1. Turn off the nearest water valve / stopcock to stop the flow.\n2. If the leak is from a pipe in the wall or ceiling, avoid that area.\n3. Place buckets or towels to contain water and prevent slip hazards.\n4. Put up a "Wet Floor" warning sign immediately.\n5. Report to the helpdesk with the exact location (room, floor, block).\n6. Take photos of the leakage before any cleanup begins.\n7. The plumber will identify the source (pipe joint, valve, fitting).\n8. Do not use electrical equipment near the water leak.\n9. If water is near electrical panels, call the electrician too.\n10. The affected area should not be used until the repair is complete and the area is dry.' },
      { title: 'Pipe Blockage / Drainage Issue', steps: '1. Stop running water through the blocked drain immediately.\n2. Do not pour chemicals into the drain without maintenance staff guidance.\n3. Check if a simple debris block (leaves, waste) can be visually cleared safely.\n4. Report to the helpdesk with the drain/pipe location.\n5. The plumber will use appropriate tools (plunger, drain snake) to clear the blockage.\n6. High-pressure water jetting may be used for severe blockages.\n7. Avoid pouring cooking oils, food waste, or solid material down drains.\n8. Check and clean drain traps regularly as a preventive measure.\n9. If the blockage causes sewage backflow, treat it as an urgent health hazard.\n10. The area should be sanitized after the blockage is cleared.' },
      { title: 'Tap Damage / Dripping Tap', steps: '1. Turn off the water supply valve under the sink or near the tap.\n2. Place a bucket under the tap to catch dripping water.\n3. Do not try to force the tap open or closed as this can worsen damage.\n4. Report the location and nature of the problem to the helpdesk.\n5. The plumber will replace the washer, O-ring, or cartridge as needed.\n6. Continuously dripping taps waste large amounts of water — treat as medium priority.\n7. The tap body or fitting may need full replacement if the thread is stripped.\n8. Ensure the replacement tap matches campus standards.\n9. Test the tap after repair to confirm no further drips.\n10. Remind users to not over-tighten taps after use to prevent damage.' },
      { title: 'Toilet Water Issue / Overflow', steps: '1. Do not flush the toilet again if it is blocked or overflowing.\n2. Close the water supply valve at the base of the toilet.\n3. Place "Out of Order" sign on the toilet stall immediately.\n4. Inform nearby users to use alternative restroom facilities.\n5. Place towels or absorbent material around the base to contain overflow.\n6. Report to the helpdesk marked as HIGH priority — this is a hygiene issue.\n7. The plumber will clear the blockage using a plunger or drain auger.\n8. The cistern float valve may need adjustment or replacement if it is continuously running.\n9. The toilet pan may need replacement if it is cracked.\n10. Thoroughly disinfect and sanitize the area after repair is done.' },
      { title: 'No Water Supply in Campus Area', steps: '1. Check if the issue is campus-wide or limited to a specific block/floor.\n2. Check if there is a planned water supply shutdown (notice board/email).\n3. Verify main water meter/supply valve is open.\n4. Check the campus water storage tanks — they may be empty.\n5. Report to the helpdesk with affected area details.\n6. The plumber will check the pump, valve, and supply lines.\n7. A water tanker may be arranged temporarily for essential requirements.\n8. If a main pipe burst has been detected, the municipal authority must be contacted.\n9. Alternative water containers (bottles, drums) to be arranged for washroom use.\n10. Inform students and staff through official channels about the issue and estimated restoration time.' },
      { title: 'Washroom Hand Wash Basin Not Draining', steps: '1. Check if debris (soap, hair) is visibly blocking the drain.\n2. Remove visible blockage carefully with gloves.\n3. Do not use the basin further until drainage is restored.\n4. Report to the helpdesk with the washroom and block details.\n5. The plumber will inspect and clear the trap under the basin.\n6. A drain snake or hand auger will be used for deeper blockages.\n7. The P-trap may need to be removed and cleaned.\n8. After clearing, flush with hot water to verify full drainage.\n9. Install a hair/debris catcher on the drain as a preventive measure.\n10. Sanitize the basin and surrounding area after the plumber completes work.' },
      { title: 'Water Cooler / Dispenser Leaking', steps: '1. Switch off and unplug the water cooler/dispenser immediately.\n2. Place a bucket under the leak to prevent water damage.\n3. Do not place any electrical device on/near the leaked water.\n4. Report to the helpdesk with the location and model of the cooler if visible.\n5. The plumber/technician will inspect the water line connections.\n6. The float valve, water tank, or pipe connection may need replacement.\n7. Ensure the water jug/bottle is correctly placed to prevent spills.\n8. If the cooling unit is leaking refrigerant, call an AC technician.\n9. Test the cooler thoroughly after repair before reconnecting to power.\n10. Schedule regular servicing for water coolers every 6 months.' },
      { title: 'Water Pump Not Working', steps: '1. Check if the campus experiences low or no water supply in the building.\n2. Check the pump control panel for error lights or tripped breakers.\n3. Verify that the pump has power supply.\n4. Check if the water storage tank is empty (the pump may have tripped on dry run).\n5. Do not attempt to restart the pump if the tank is empty — the pump will burn.\n6. Report to the helpdesk and the electrician/plumber together.\n7. The plumber will check the pump motor, impeller, and valves.\n8. The electrician will check power supply to the pump.\n9. If the pump motor has failed, a replacement will be arranged.\n10. Install a float switch / auto-cutoff to prevent dry running in future.' },
      { title: 'Hot Water Not Available', steps: '1. Check if the geyser/boiler power switch is on.\n2. Check if the geyser thermostat has tripped (press the reset button if applicable).\n3. Check if the geyser element indicator light is active.\n4. Report to the helpdesk with the location of the geyser/boiler.\n5. The electrician/plumber will inspect the heating element.\n6. The thermostat may need calibration or replacement.\n7. If the geyser tank is cracked or corroded, it needs replacement.\n8. Ensure the water supply to the geyser is not blocked.\n9. A pressure relief valve failure can also prevent hot water — check it.\n10. Schedule annual descaling of the geyser to maintain efficiency.' },
      { title: 'Foul Smell from Drains/Pipes', steps: '1. Check if the smell is from a dry P-trap (pour water into unused drains).\n2. Avoid using the affected washroom/kitchen area if the smell is strong.\n3. Report to the helpdesk - foul smell may indicate sewer gas leak (health hazard).\n4. The plumber will inspect drain U-traps and venting pipes.\n5. A sewer gas inspection may be needed to test for toxic gases.\n6. Blocked sewer vents on the rooftop may be the cause.\n7. The drain may need a thorough disinfectant flush.\n8. Ensure waste bins in washrooms are emptied daily.\n9. Regular drain cleaning with enzyme cleaners by housekeeping staff is recommended.\n10. If structural pipe damage is suspected, a CCTV drain inspection may be conducted.' },
      { title: 'Water Pressure Too Low', steps: '1. Check if low pressure affects only one tap/fixture or the entire building.\n2. Clean the tap aerator and showerhead to remove mineral deposits.\n3. Check if the main water valve is fully open.\n4. Verify water storage tank levels on campus.\n5. Report to helpdesk with affected locations and pressure measurements if available.\n6. The plumber will check pressure regulator and pump settings.\n7. Clogged pipes or sediment buildup may need flushing.\n8. Water pump capacity may need upgrading for higher floors.\n9. Install booster pumps if pressure issues are chronic.\n10. Schedule regular maintenance of water distribution system.' },
      { title: 'Burst Water Pipe Emergency', steps: '1. Immediately shut off main water supply to prevent flooding.\n2. Evacuate the area if water is near electrical equipment.\n3. Call emergency services and campus security immediately.\n4. Take photos for insurance and maintenance records.\n5. Move valuable equipment and furniture away from water.\n6. Place warning signs and barriers around the flooded area.\n7. Contact professional water damage restoration services.\n8. Report to administration and facilities management urgently.\n9. Document all damage for insurance claims.\n10. Ensure area is completely dry before allowing re-entry.' },
      { title: 'Frozen Pipes in Winter', steps: '1. Do not use open flames or direct heat to thaw pipes.\n2. Open taps to allow water to flow once pipes begin to thaw.\n3. Apply gentle heat using hair dryer or warm towels.\n4. Check for pipe cracks or leaks after thawing.\n5. Report frozen pipe locations to maintenance immediately.\n6. The plumber will inspect for pipe damage after thawing.\n7. Insulate exposed pipes to prevent future freezing.\n8. Keep building temperature above freezing during cold weather.\n9. Allow taps to drip slightly during extreme cold to prevent freezing.\n10. Install pipe heating cables in areas prone to freezing.' },
      { title: 'Sump Pump Failure', steps: '1. Check if basement or lower levels are experiencing flooding.\n2. Verify sump pump has power and is not unplugged.\n3. Check if the float switch is stuck or obstructed.\n4. Listen for unusual noises from the pump motor.\n5. Do not enter flooded areas with electrical equipment.\n6. Report pump failure to maintenance as high priority.\n7. The plumber will test pump motor and electrical connections.\n8. Clean debris from sump pit that may clog the pump.\n9. Install backup pump system for critical areas.\n10. Schedule regular testing and maintenance of sump pumps.' },
      { title: 'Backflow Prevention Device Issues', steps: '1. Check if water is flowing backwards into the campus water system.\n2. Look for signs of contaminated water or unusual discoloration.\n3. Stop using water from affected taps immediately.\n4. Report suspected backflow to health department and facilities.\n5. The plumber will test backflow prevention devices.\n6. Devices may need cleaning, repair, or replacement.\n7. Annual testing is required for all backflow prevention systems.\n8. Install additional backflow preventers where required by code.\n9. Train maintenance staff on backflow prevention system operation.\n10. Maintain documentation of all backflow prevention device testing.' },
    ],
  },
  {
    name: 'Furniture',
    solutions: [
      { title: 'Broken Chair', steps: '1. Immediately take the broken chair out of use.\n2. Tag it clearly with "Broken — Do Not Use" label.\n3. Move it to a designated storage/repair area away from classrooms.\n4. Report to the helpdesk with the classroom number and type of chair.\n5. The maintenance team will assess if the chair can be repaired or needs replacement.\n6. Minor breaks (screws, bolts) can be repaired by the carpenter.\n7. Structural frame damage usually requires full replacement.\n8. Arrange a spare chair in the interim from the storage facility.\n9. Check remaining chairs in the room for similar wear and tear.\n10. Suggest procurement of replacement chairs to the administration if the count falls below required numbers.' },
      { title: 'Damaged / Broken Desk', steps: '1. Stop using the damaged desk immediately.\n2. Label it "Damaged — Do Not Use" and move it aside if possible.\n3. Ensure no sharp edges are exposed that could injure students.\n4. Report to the helpdesk with the classroom and desk description.\n5. The carpenter will inspect for loose tops, cracked surfaces, or broken frames.\n6. Minor surface damage can be sanded and repainted.\n7. Structural damage (broken legs, frame) requires full replacement.\n8. Organize spare desks from storage as temporary replacements.\n9. Log the number of damaged desks to plan batch procurement.\n10. Regularly inspect furniture as part of room maintenance checks.' },
      { title: 'Loose Table Screws / Wobbling Table', steps: '1. Place a "Caution" sign on the table to prevent toppling accidents.\n2. Do not place heavy objects on a wobbling/unstable table.\n3. Report to the helpdesk with the classroom number.\n4. The carpenter will tighten/replace loose screws and bolts.\n5. Thread-lock adhesive may be applied to prevent screws from loosening again.\n6. Rubber leveler feet may be adjusted / replaced to stabilize the table.\n7. If the frame joint is cracked, the table will need structural repair.\n8. Check all legs for equal contact with the floor after repair.\n9. After tightening, test the table under normal weight load.\n10. Include table tightening in the monthly furniture maintenance checklist.' },
      { title: 'Broken Cupboard / Cabinet', steps: '1. Do not force open or close a damaged cupboard door or drawer.\n2. If it is locked and the lock is broken, call a locksmith or maintenance staff.\n3. Remove valuables from the cupboard if it cannot be secured.\n4. Report to the helpdesk with the location and type of cupboard.\n5. The carpenter will inspect hinges, handles, locks, and the frame.\n6. Broken hinges and handles are easy replacements.\n7. A cracked or warped door panel may need full replacement.\n8. Wooden cupboards damaged by moisture may need full replacement.\n9. Metal cupboards can usually be repaired by a welder.\n10. Ensure repaired cupboards can be properly locked before handover.' },
      { title: 'Whiteboard / Blackboard Damage', steps: '1. Check if the board surface is cracked, has permanent stains or deep scratches.\n2. Report to the helpdesk with the classroom number and nature of damage.\n3. Try whiteboard cleaning solution before concluding that the surface is unusable.\n4. A cracked board is a safety hazard — stop use and report immediately.\n5. The maintenance team will assess if re-surfacing or replacement is needed.\n6. A whiteboard surface restoration kit may be used for minor damage.\n7. Full replacement will be arranged for severely damaged boards.\n8. Ensure the replacement board is the same size as the classroom requires.\n9. Inform the teacher using the room and arrange an alternative (portable board).\n10. Confirm board is properly mounted and usable before closing the ticket.' },
      { title: 'Broken Classroom Door / Hinge', steps: '1. If the door cannot be closed/locked, report it as a SECURITY concern.\n2. Tie or prop the door safely to avoid it swinging violently.\n3. Report to the helpdesk with the classroom number and block.\n4. The carpenter will assess hinge wear, frame alignment, and door condition.\n5. Loose hinges can be retightened or replaced quickly.\n6. A warped or swollen door may need to be planed (trimmed).\n7. A broken door lock cylinder needs to be replaced by a locksmith.\n8. The door frame may need repair if the door has pulled away from it.\n9. Ensure the new lock keys are distributed appropriately.\n10. Test the door closure and lock operation after repair.' },
      { title: 'Bench / Stadium-style Seating Damage', steps: '1. Mark damaged sections of the bench with visible tape or cones.\n2. Do not allow students to sit on a broken bench.\n3. Report to the helpdesk with the hall/stadium area name and section.\n4. The carpenter will assess if planks, bolts, or the frame is damaged.\n5. Individual planks can be replaced without replacing the whole bench.\n6. Rust-damaged metal frames may need welding or angle iron reinforcement.\n7. Wood-treated or painted surfaces should be refinished after repair.\n8. Conduct a full sweep of seating before major campus events.\n9. Bench capacity load must be respected — overcrowding causes damage.\n10. Include bench inspection in pre-event infrastructure checks.' },
      { title: 'Reading Room / Library Table Damage', steps: '1. Move the damaged table away from the active reading area.\n2. Label it clearly and inform the librarian.\n3. Report to the helpdesk with the library section (zone/room) and description.\n4. The carpenter will inspect the table for surface and structural integrity.\n5. Surface damage can be repaired with laminate or paint.\n6. Broken legs or a damaged frame need structural repair or replacement.\n7. Consider the table\'s load-bearing needs for books and computers.\n8. Place a temporary table from storage if urgently needed.\n9. Inspect other tables in the library for similar wear.\n10. Confirm repair and quality check before returning the table to use.' },
      { title: 'Staff Room Furniture Damage', steps: '1. Report to the helpdesk with room name, furniture type, and description.\n2. The administration office should also be notified for staff areas.\n3. The carpenter will assess and perform repair or arrange replacement.\n4. Office chairs with broken castors or armrests can be repaired.\n5. Staff meeting tables with broken sections will be repaired or replaced.\n6. Ensure replacement furniture maintains the quality standard.\n7. Store damaged furniture away from the working area to maintain appearance.\n8. Consider ergonomic furniture replacements for staff wellbeing.\n9. Budget approval from administration may be needed for full replacement.\n10. Confirm with the staff room occupants that the repair is satisfactory.' },
      { title: 'Storage Rack / Shelf Collapsed or Damaged', steps: '1. Clear all items from the damaged shelf or rack immediately.\n2. If a collapse has occurred, check for any injuries first.\n3. Do not place items back on a damaged shelf.\n4. Report to the helpdesk with the location and type of rack/shelf.\n5. The carpenter/welder will assess the structural integrity.\n6. Overloading is the most common cause — redistribute load if needed.\n7. Wall-mounted shelves need anchor bolt verification.\n8. Freestanding racks must be secured (wall-anchored) to prevent tipping.\n9. Replace damaged brackets, screws, or entire sections as needed.\n10. Load testing after repair confirms safety before items are replaced on the shelf.' },
      { title: 'Office Chair Wheels/Castors Not Rolling', steps: '1. Check if wheels are clogged with dust, hair, or debris.\n2. Clean wheels using a damp cloth and remove entangled material.\n3. Lubricate wheel axles with appropriate lubricant if stiff.\n4. Check if wheels are securely attached to the chair base.\n5. Report to helpdesk if wheels are cracked or need replacement.\n6. The maintenance team will source compatible replacement wheels.\n7. Ensure replacement wheels are appropriate for floor type (hard/soft).\n8. Test chair mobility after wheel replacement or cleaning.\n9. Regular maintenance prevents wheel failure - schedule periodic cleaning.\n10. Consider upgrading to heavy-duty wheels for frequently used chairs.' },
      { title: 'Whiteboard/Blackboard Not Erasable', steps: '1. Try cleaning with appropriate board cleaner and microfiber cloth.\n2. For whiteboards, use isopropyl alcohol for stubborn marks.\n3. For blackboards, use damp cloth followed by dry cloth.\n4. Check if permanent markers were used on whiteboard by mistake.\n5. Report to helpdesk if board surface is permanently stained or damaged.\n6. The maintenance team will attempt professional cleaning methods.\n7. Board resurfacing may be required for severely damaged surfaces.\n8. Replace board if cleaning and resurfacing are ineffective.\n9. Educate users on proper markers/chalk to prevent future damage.\n10. Consider installing additional boards if current capacity is insufficient.' },
      { title: 'Filing Cabinet Drawers Stuck/Jammed', steps: '1. Do not force the drawer open as this may cause further damage.\n2. Check if drawer is locked and try appropriate key if available.\n3. Gently try lifting the drawer while pulling to clear any obstruction.\n4. Check if files inside are overstuffed and preventing proper closure.\n5. Report to helpdesk with cabinet location and drawer identification.\n6. The maintenance team will lubricate drawer slides and tracks.\n7. Damaged or bent drawer slides will be repaired or replaced.\n8. Reorganize files to prevent overstuffing after repair.\n9. Regular cleaning and lubrication prevents drawer jamming.\n10. Consider upgrading to modern filing systems if cabinets are frequently problematic.' },
      { title: 'Conference Table Wobbly/Unstable', steps: '1. Check if all table legs are properly tightened and touching the floor.\n2. Look for missing or loose screws, bolts, or brackets.\n3. Clear the table of all items before attempting any adjustments.\n4. Report to helpdesk with conference room name and table description.\n5. The carpenter will inspect table structure and joints.\n6. Loose connections will be tightened with appropriate tools.\n7. Damaged table legs or frame sections may need replacement.\n8. Table leveling feet can be adjusted to compensate for uneven floors.\n9. Heavy-duty brackets may be installed for reinforcement if needed.\n10. Consider table replacement if structural damage is beyond repair.' },
      { title: 'Locker Door Won\'t Open/Close Properly', steps: '1. Check if the correct combination or key is being used.\n2. Try operating the lock mechanism gently - avoid forcing it.\n3. Look for visible obstructions in the door frame or hinge area.\n4. Check if locker door is warped or frame is bent.\n5. Report to helpdesk with locker number and bank location.\n6. The maintenance team will inspect lock mechanism and door alignment.\n7. Lock may need lubrication, adjustment, or complete replacement.\n8. Bent door frames can often be straightened with proper tools.\n9. Replace damaged locks with same type for key compatibility.\n10. Schedule regular inspection of all lockers to prevent similar issues.' },
    ],
  },
  {
    name: 'Cleaning / Housekeeping',
    solutions: [
      { title: 'Trash Overflow in Campus Area', steps: '1. Do not allow the overflowing waste to block walkways.\n2. Report to the helpdesk and housekeeping supervisor immediately.\n3. Include the exact location (building, floor, corridor section).\n4. Housekeeping staff will empty and replace the bin liner without delay.\n5. Segregate dry and wet waste as per campus waste management policy.\n6. Temporarily place an extra collection bag beside the bin if housekeeping is delayed.\n7. Do not dump waste outside the bin area — it creates pest problems.\n8. Review bin collection schedule — frequency may need to increase for busy areas.\n9. Request additional or larger bins in consistently high-waste areas.\n10. Raise a housekeeping review ticket if this is a recurring issue in the same location.' },
      { title: 'Dirty / Unhygienic Classroom', steps: '1. Report to the housekeeping supervisor and helpdesk before class starts.\n2. State the classroom number, block, and the specific hygiene issue.\n3. Housekeeping staff will be dispatched immediately for urgent cleaning.\n4. Do not hold class in an area that is deemed unhygienic or unsafe.\n5. The shift supervisor will assign cleaning staff to the affected classroom.\n6. Common causes: previous session litter, food debris, spilt liquids.\n7. An interim clean (sweep, wipe) will be performed before use.\n8. A full deep-clean will be scheduled at the end of the day.\n9. Students are encouraged to leave the classroom in the state they found it.\n10. Recurring issues in the same classroom should be escalated for schedule review.' },
      { title: 'Washroom Not Cleaned / Unhygienic', steps: '1. Report to the housekeeping supervisor and helpdesk immediately — this is a health priority.\n2. Specify washroom location (building, floor, gender).\n3. Temporarily place an "Under Cleaning" sign if needed.\n4. Housekeeping staff will be sent immediately as this is a high-priority job.\n5. The cleaning will include scrubbing floors, sanitizing fittings, and restocking supplies.\n6. Check if soap, tissue, and hand sanitizer dispensers are stocked.\n7. Report any broken fittings (mirrors, dispensers) alongside cleaning issues.\n8. Housekeeping supervisors must sign-off on washroom inspections multiple times a day.\n9. If the washroom has been out of service for a known reason, put up appropriate signage and direct users.\n10. A washroom cleaning log must be maintained at each facility.' },
      { title: 'Corridor / Campus Path Cleaning Needed', steps: '1. Report to the helpdesk with the specific corridor or path area.\n2. Indicate the urgency — spills are a slip hazard and should be marked immediately.\n3. Housekeeping staff will mop, sweep, and clean the reported area.\n4. Place "Wet Floor" cones for wet surfaces to prevent slip-and-fall accidents.\n5. Dry mopping of entire corridors should be done at the start of each shift.\n6. Deep corridor cleaning (mopping with disinfectant) should be done daily.\n7. Remove any debris, leaves, or obstacles from campus pathways.\n8. Garden waste near entrances should be cleared by the campus grounds team.\n9. High-footfall areas may need more than one cleaning per shift.\n10. Share feedback with the housekeeping supervisor if quality is consistently below standard.' },
      { title: 'Spill Cleanup Required Urgently', steps: '1. Alert nearby users to avoid the spill area to prevent slipping.\n2. Place a "Wet Floor" warning cone or sign immediately.\n3. Call housekeeping directly or raise an urgent ticket.\n4. Do not attempt to wipe chemical spills without knowing what the substance is.\n5. For water spills, emergency mopping with absorbent material can be done by anyone safely.\n6. For chemical or laboratory spills, follow the lab safety protocol and evacuate if needed.\n7. The housekeeping team will clean and sanitize the area.\n8. If there is an injury due to the spill, file an incident report.\n9. Identify the cause of the spill and prevent recurrence.\n10. Confirm the floor is dry and safe before allowing foot traffic to resume.' },
      { title: 'Pest Issue (Cockroaches / Rats / Insects)', steps: '1. Do not leave food waste uncovered in classrooms or offices.\n2. Report the pest sighting to the helpdesk with the exact location and type of pest.\n3. The housekeeping team will arrange emergency pest control treatment.\n4. Affected areas will be cleared before pest control spray/treatment.\n5. Seal all food items and clear all waste from the treated area.\n6. Students/staff will be asked to vacate the area during treatment.\n7. Fumigation or gel-bait treatment will be conducted by a licensed pest control vendor.\n8. Allow adequate time for ventilation before re-occupying treated spaces.\n9. Follow-up inspections within 1 week to confirm effectiveness.\n10. Establish a quarterly campus-wide pest control schedule.' },
      { title: 'Canteen / Food Area Cleaning', steps: '1. Report any food preparation area hygiene issues to the helpdesk and canteen supervisor.\n2. Tables must be wiped after each use by canteen staff.\n3. Food spillage on the floor must be cleaned within 5 minutes.\n4. Dustbins in the canteen must be emptied at least 3 times a day.\n5. Exhaust fans and ventilation must be working — report if faulty.\n6. Any pest sighting in the canteen must be treated as an emergency.\n7. The canteen area must be deep-cleaned every day after closing.\n8. Health inspections of the canteen are to be conducted monthly.\n9. Food handlers must maintain personal hygiene standards.\n10. Non-compliance with hygiene standards should be reported to the administration.' },
      { title: 'Garbage Collection Not Done on Schedule', steps: '1. Report to the housekeeping supervisor and helpdesk.\n2. Escalate if bins are overflowing as a result of missed collection.\n3. The supervisor will confirm the collection status and dispatch staff.\n4. Temporary bins may be placed to manage excess waste.\n5. Identify if the delay is due to staff shortage or equipment issue.\n6. Adjust the waste collection schedule if a particular area generates more waste.\n7. All waste areas should be cleared before the end of each working day.\n8. Coordinate with the municipal authority for external garbage pick-up schedule.\n9. Ensure segregation of biodegradable and non-biodegradable waste.\n10. Review and publish the housekeeping schedule for staff accountability.' },
      { title: 'Glass / Sharp Object on Campus Ground', steps: '1. Alert everyone in the area immediately — do not let anyone walk through.\n2. Barricade the area with cones or temporary barriers.\n3. Report to housekeeping and the helpdesk as a safety emergency.\n4. Only trained housekeeping staff should handle broken glass — using thick gloves and proper tools.\n5. Never pick up broken glass with bare hands.\n6. Sweep the glass into a puncture-proof container (not a regular bin).\n7. Inspect the wider area for scattered fragments.\n8. Check for injuries — provide first aid if needed and file an incident report.\n9. Dispose of the sharp waste in a clearly labelled sharps/hazard bin.\n10. Investigate the source (broken window, furniture, glassware) and report for repair.' },
      { title: 'Bad Odour in Campus Area', steps: '1. Identify the source of the smell (blocked drain, garbage, stagnant water, spoiled food).\n2. Report to the helpdesk with a description of the smell type and location.\n3. Check if nearby bins are overflowing or drains are blocked.\n4. Housekeeping will clean, deodorize, and ventilate the area.\n5. Open windows and doors to increase ventilation where possible.\n6. Check air conditioning ducts — mold or debris inside ducts causes bad odors.\n7. Report a plumbing issue alongside if the smell is sewer-like.\n8. The area should be vacated if the smell is strong and potentially hazardous (gas smell).\n9. If the smell persists after cleaning, an HVAC or plumbing inspection is needed.\n10. Use campus-approved air fresheners in washrooms and enclosed corridors.' },
      { title: 'Floor/Carpet Stains Need Deep Cleaning', steps: '1. Identify the type of stain (food, beverage, ink, mud, etc.) for proper treatment.\n2. Cordon off the stained area to prevent further contamination.\n3. Report to housekeeping with stain location and suspected cause.\n4. For immediate spills, blot (don\'t rub) with clean absorbent material.\n5. Housekeeping will use appropriate cleaning agents for stain type.\n6. Professional carpet cleaning equipment may be required for deep cleaning.\n7. Allow adequate drying time before allowing foot traffic.\n8. For persistent stains, specialized stain removal services may be needed.\n9. Consider protective treatments for high-traffic carpeted areas.\n10. Document cleaning procedures for quality assurance and repeat issues.' },
      { title: 'Graffiti/Vandalism on Campus Walls', steps: '1. Document the graffiti with photos for security and maintenance records.\n2. Report to campus security and helpdesk immediately.\n3. Cover offensive graffiti temporarily until proper removal.\n4. Do not attempt to remove graffiti with unauthorized chemicals.\n5. Housekeeping will assess appropriate removal methods for surface type.\n6. For painted walls, matching paint may be needed after cleaning.\n7. Pressure washing may be effective for exterior concrete surfaces.\n8. Report vandalism to local authorities if it involves hate speech or threats.\n9. Consider installing security cameras in areas prone to vandalism.\n10. Organize community clean-up events to maintain campus appearance.' },
      { title: 'Air Freshener/Soap Dispensers Empty', steps: '1. Check all dispensers in the area to determine scope of restocking needed.\n2. Report locations of empty dispensers to housekeeping supervisor.\n3. For soap dispensers, verify if the issue is empty refill or dispenser malfunction.\n4. Housekeeping will refill dispensers according to established schedule.\n5. Check dispenser mechanisms for clogs or damage during refilling.\n6. Replace malfunctioning dispensers with working units promptly.\n7. Implement tracking system to monitor refill schedules and usage rates.\n8. Consider installing larger capacity dispensers in high-traffic areas.\n9. Train housekeeping staff on proper refilling procedures.\n10. Maintain adequate inventory of refill supplies to prevent stockouts.' },
      { title: 'Lost and Found Items Accumulation', steps: '1. Collect all unattended items from classrooms, corridors, and common areas.\n2. Log each item with description, location found, and date.\n3. Establish central lost and found location with proper cataloging.\n4. Announce found items through campus communication channels.\n5. Store items securely to prevent damage or additional loss.\n6. Create claim process requiring identification verification.\n7. Set retention period policy (typically 30-90 days) for unclaimed items.\n8. Donate unclaimed items to charity after retention period expires.\n9. Maintain records of disposed items for accountability.\n10. Post lost and found procedures prominently around campus.' },
      { title: 'Window Cleaning Required', steps: '1. Assess which windows need cleaning (interior, exterior, or both sides).\n2. Check accessibility and safety requirements for exterior window cleaning.\n3. Report to housekeeping with specific building and floor details.\n4. Remove window treatments (curtains, blinds) if they obstruct cleaning.\n5. Professional window cleaning equipment may be required for high floors.\n6. Use appropriate cleaning solutions to avoid streaking or damage.\n7. Clean window frames and sills along with glass surfaces.\n8. Inspect windows for damage (cracks, seal failure) during cleaning.\n9. Schedule regular window cleaning to maintain campus appearance.\n10. Consider professional window cleaning service for multi-story buildings.' },
    ],
  },
  {
    name: 'Security',
    solutions: [
      { title: 'Unauthorized Entry on Campus', steps: '1. Alert the security guard at the gate or nearest post immediately.\n2. Do not confront the unauthorized individual alone.\n3. Call campus security control room.\n4. Report to the helpdesk with the location and description of the individual.\n5. Security team will approach and verify identification.\n6. If the individual refuses to cooperate, local police may be called.\n7. CCTV footage will be reviewed for the reported time and location.\n8. All entrances should require ID verification and visitor log entry.\n9. Access control systems (barriers, card readers) should be activated at all entry points.\n10. Conduct a review of entry procedures to identify how unauthorized access occurred.' },
      { title: 'Suspicious Activity Observed', steps: '1. Do not place yourself in danger — observe from a safe distance.\n2. Alert the security guard at the nearest post immediately.\n3. Call the campus security control room.\n4. Submit a helpdesk ticket describing the suspicious activity, time, and location.\n5. Do not take photos or videos if it puts you at risk.\n6. Describe the individual(s)/vehicle as accurately as possible (clothing, direction, etc.).\n7. Evacuate the immediate area if you feel threatened.\n8. Security will investigate and review CCTV footage.\n9. If a crime is suspected, law enforcement will be notified.\n10. All reports of suspicious activity are taken seriously — always report, do not ignore.' },
      { title: 'CCTV Camera Not Working', steps: '1. Report to the helpdesk and security supervisor with the exact camera location or ID.\n2. The security team will confirm if the issue is with the camera, DVR/NVR, or network.\n3. Check if the camera power LED is active.\n4. The IT/security technician will access the DVR/NVR to diagnose the fault.\n5. A cable connectivity issue may be identified and repaired.\n6. The camera lens may need cleaning if the image is blurred.\n7. Camera firmware may need updating if it is displaying errors.\n8. A replacement camera will be installed if hardware failure is confirmed.\n9. Ensure the camera\'s field of view is correct after reinstallation.\n10. Increased physical security patrols will cover the camera gap until it is repaired.' },
      { title: 'Gate / Barrier Not Functioning', steps: '1. Manually open or close the gate/barrier to ensure access is not blocked.\n2. Do not leave the gate unsecured — a guard must stand by if the mechanism fails.\n3. Report to the helpdesk and the security supervisor immediately.\n4. The technician will inspect the motor, sensor, control panel, and power supply.\n5. Common causes: power failure, motor overload, sensor blockage.\n6. Ensure the area around the barrier is clear of obstructions.\n7. A manual override code/key should always be accessible to authorized staff.\n8. Do not allow vehicles to force the barrier — damage will result.\n9. The repair team will source spare parts if the motor or mechanism needs replacement.\n10. Test the barrier fully through multiple operation cycles before declaring it fixed.' },
      { title: 'Lost / Stolen Property on Campus', steps: '1. Report the loss/theft to campus security and the helpdesk.\n2. File a written complaint with the security office.\n3. Describe the item (type, color, serial number, value) and where/when it was last seen.\n4. Security will review CCTV footage from the relevant area and time.\n5. Circulate a notice to staff/students (via admin) if appropriate.\n6. A First Information Report (FIR) may need to be filed with local police for theft.\n7. Recovered items will be kept in the security office for owner verification.\n8. All valuable items should be stored in locked lockers or rooms.\n9. Do not leave valuables unattended on desks, in classrooms, or common areas.\n10. Campus liability policy regarding personal belongings will be communicated.' },
      { title: 'Campus Emergency / Threat Alert', steps: '1. Immediately call campus security emergency number and local emergency services (100/112).\n2. Activate the campus emergency alarm if available.\n3. Evacuate all students and staff from the affected area via designated routes.\n4. Do not use elevators during an emergency evacuation.\n5. Assemble at the designated muster/gathering point.\n6. Account for all persons under your supervision — report any missing individuals.\n7. Do not re-enter the building until cleared by security/emergency services.\n8. Campus security will coordinate with police, fire brigade, or ambulance.\n9. Administration will activate the crisis management/communication protocol.\n10. A post-incident report will be filed and a review conducted to improve preparedness.' },
      { title: 'Access Card / ID Card Not Working', steps: '1. Check if the card is physically damaged, bent, or demagnetized.\n2. Try the card at a different reader to determine if it is a card or reader issue.\n3. Report to the helpdesk and security/admin office with your ID details.\n4. The access control administrator will check card status in the system.\n5. Cards may expire or be deactivated — this is a common cause.\n6. A temporary access pass will be issued while the issue is resolved.\n7. A replacement card will be issued if the original is damaged or lost.\n8. Inform the security team if the card has been lost — it must be deactivated immediately.\n9. Do not lend your access card to others — it is a security violation.\n10. Report if you suspect your card has been misused.' },
      { title: 'Student Conflict / Altercation on Campus', steps: '1. Do not attempt to physically intervene between disputing parties.\n2. Alert campus security immediately.\n3. Call the helpdesk and report the location and nature of the conflict.\n4. Separate the individuals by directing them to different areas (for trained security only\n5. Campus counsellors or the student affairs officer will be called.\n6. Witnesses may be interviewed by security.\n7. CCTV footage will be reviewed.\n8. Disciplinary procedures will be initiated by the administration if policy violations occurred.\n9. All parties involved will be required to provide a written statement.\n10. Counselling support will be offered to those affected.' },
      { title: 'Vandalism / Property Damage', steps: '1. Report the vandalism to campus security and the helpdesk immediately.\n2. Do not disturb the scene — preserve evidence for investigation.\n3. Photograph the damage for documentation.\n4. Security will review CCTV footage to identify suspect(s).\n5. A written incident report will be filed by the security team.\n6. A First Information Report may be filed with local police if criminal damage has occurred.\n7. The maintenance team will be tasked with repair/restoration.\n8. Identified suspects will face disciplinary action under campus regulations.\n9. Public notice may be issued to deter future vandalism.\n10. Review and upgrade campus surveillance coverage of the affected area.' },
      { title: 'Fire or Smoke Detected on Campus', steps: '1. IMMEDIATELY activate the fire alarm / pull the nearest fire alarm station.\n2. Call the fire brigade (101) and campus security.\n3. Alert and evacuate all occupants from the building — do not use the lift.\n4. Do not re-enter the building for any reason.\n5. Use fire extinguishers ONLY if trained and ONLY on small, manageable fires.\n6. Assemble at the designated fire muster/assembly point.\n7. Campus security to take charge of evacuation and head count.\n8. The fire brigade will have full authority once they arrive.\n9. Utilities (gas, electricity) will be shut off by maintenance staff if safe to do so.\n10. A full post-incident fire safety review will be conducted before building is re-occupied.' },
      { title: 'Parking Area Security Issues', steps: '1. Report any suspicious activity around parked vehicles to security immediately.\n2. Document incidents involving vehicle damage or break-ins with photos.\n3. Ensure all parking areas have adequate lighting for security.\n4. Report malfunctioning parking area lights to maintenance.\n5. Verify that security cameras cover all parking zones effectively.\n6. Implement and maintain vehicle entry/exit logs at security gates.\n7. Ensure parking permits are properly displayed and verified.\n8. Report unauthorized vehicles or those blocking access routes.\n9. Coordinate with local police for serious parking area crimes.\n10. Review and upgrade parking area security measures regularly.' },
      { title: 'Lock/Key Security Compromise', steps: '1. Report lost or stolen keys to security and administration immediately.\n2. Document which areas or rooms the compromised keys provide access to.\n3. Change locks immediately in critical areas like server rooms, labs.\n4. Implement temporary security measures for affected areas.\n5. Audit all key distributions and update access logs.\n6. Consider upgrading to electronic access control systems.\n7. Report suspected unauthorized key duplication attempts.\n8. Establish strict key management and tracking procedures.\n9. Train staff on proper key security protocols.\n10. Conduct regular security assessments of physical access controls.' },
      { title: 'Cyber Security Incident on Campus Network', steps: '1. Disconnect affected systems from the network immediately.\n2. Do not attempt to clean infected systems without IT support.\n3. Report the incident to IT security team and administration urgently.\n4. Document what was happening when the incident was discovered.\n5. Preserve evidence - do not delete files or clear browser history.\n6. Change passwords for all accounts that may have been compromised.\n7. Notify relevant authorities if sensitive data was potentially accessed.\n8. Implement additional security measures while investigation is ongoing.\n9. Provide security awareness training to prevent future incidents.\n10. Review and update cyber security policies and procedures.' },
      { title: 'Visitor Management System Issues', steps: '1. Verify visitor identity using valid government-issued photo ID.\n2. Ensure all visitors are properly logged in the visitor management system.\n3. Issue temporary visitor badges that clearly indicate access levels.\n4. Assign escorts for visitors to restricted areas when required.\n5. Monitor visitor badge returns and ensure all are accounted for.\n6. Report system malfunctions to IT support for immediate repair.\n7. Maintain backup paper logs when digital system is unavailable.\n8. Conduct regular security briefings for front desk and security staff.\n9. Review visitor access logs regularly for unusual patterns.\n10. Update visitor management procedures based on security assessments.' },
      { title: 'Alarm System Malfunctions', steps: '1. Test all alarm systems monthly to ensure proper operation.\n2. Report any false alarms to security and maintenance immediately.\n3. Check alarm system power supply and backup battery status.\n4. Verify all sensors and detectors are clean and unobstructed.\n5. Update alarm system codes and access credentials regularly.\n6. Coordinate with alarm monitoring service provider for system issues.\n7. Maintain detailed logs of all alarm activations and responses.\n8. Train security personnel on proper alarm response procedures.\n9. Conduct annual maintenance with certified alarm system technicians.\n10. Review and test alarm system during emergency preparedness drills.' },
    ],
  },
  {
    name: 'Infrastructure / Building Maintenance',
    solutions: [
      { title: 'Wall Damage (Cracks / Peeling)', steps: '1. Assess if the crack is structural (running from floor to ceiling, wide) or surface (hairline, cosmetic).\n2. Do not use the room if a structural crack is suspected — report as an emergency.\n3. Report to the helpdesk with the room/location and a photograph of the damage.\n4. Surface cracks will be filled with putty, sanded, and repainted.\n5. A civil/structural engineer will inspect cracks that appear to be structural.\n6. Peeling paint will be scraped, primed, and repainted.\n7. Water seepage causing peeling must be treated at the source first.\n8. The damaged area will be cordoned off during repair for safety.\n9. Post-repair, the area will be inspected by the supervisor before sign-off.\n10. Annual building inspections should identify and prevent wall deterioration early.' },
      { title: 'Ceiling Leakage', steps: '1. Place buckets or containers under the leak immediately.\n2. Put up "Wet Floor" warning signs and keep the area clear.\n3. Switch off any electrical points directly below the water leak.\n4. Report to the helpdesk as HIGH priority — ceiling leaks can cause structural and electrical damage.\n5. Photograph the leak location and visible water staining.\n6. The plumber and civil maintenance team will jointly inspect.\n7. The roof above the leak will be inspected for cracks, blocked gutters, or broken waterproofing.\n8. Ceiling boards or plaster may need to be removed to access and fix the pipe or roof.\n9. The ceiling will be repaired and repainted after the root cause is fixed.\n10. Block any academic or administrative activity below the leak until repairs are complete.' },
      { title: 'Broken Tiles (Floor or Wall)', steps: '1. Broken floor tiles are a serious slip/cut hazard — barricade the area immediately.\n2. Place warning signs and prevent foot traffic over broken tiles.\n3. Report to the helpdesk with location and number of broken tiles.\n4. The mason/tiler will remove broken tile fragments safely.\n5. Matching replacement tiles will be sourced if available in stock.\n6. New tiles will be set in adhesive and grouted to match the existing pattern.\n7. Allow sufficient curing time before the area can be walked upon.\n8. Broken wall tiles in washrooms must be replaced to maintain hygiene standards.\n9. Inspect the surrounding tiles for looseness during the repair visit.\n10. Confirm the repair quality and close the ticket after floor clearance.' },
      { title: 'Door or Window Not Closing / Damaged', steps: '1. If the door cannot be secured (locked), treat it as a SECURITY issue and report immediately.\n2. If a window is broken (glass), barricade and report as a safety hazard.\n3. Report to the helpdesk with room number and description of the issue.\n4. The carpenter will assess hinges, frame alignment, door closer mechanism, or locks.\n5. Loose hinges are a quick fix — tightened or replaced within the repair visit.\n6. A swollen/warped door may need planing (trimming) to close properly.\n7. Broken window glass will be replaced with safety glass.\n8. Window locks and latches will be checked and replaced if faulty.\n9. Confirm the door/window closes and locks fully after repair.\n10. Report ongoing issues (door warping seasonally) for a permanent fix.' },
      { title: 'Staircase / Railing Damage', steps: '1. If the railing is missing or broken — barricade the staircase and divert foot traffic.\n2. Do not use a staircase with loose/missing railings — fall hazard.\n3. Report to the helpdesk as a HIGH priority safety concern.\n4. Photograph the damage and share with the maintenance team.\n5. The welder/carpenter will repair or replace the damaged section.\n6. Stair nosings (edge covers) must be intact to prevent trips.\n7. Ensure repairs meet safety standards for load-bearing capacity.\n8. The staircase will be unavailable during repair — alternative access route must be communicated.\n9. Full inspection of all railings on the same staircase should be conducted.\n10. The repaired section must be tested for stability before reopening the staircase.' },
      { title: 'Roof / Terrace Structural Issue', steps: '1. Vacate the area below if there is a risk of collapse or falling debris.\n2. Report immediately to the helpdesk and administration — this is an emergency.\n3. A structural engineer must assess the roof before any other work begins.\n4. Do not attempt any DIY repair on a roof.\n5. Terrace access should be restricted until clearance is given.\n6. Loose roofing sheets, tiles, or concrete must be secured or removed safely.\n7. Waterproofing treatment will be applied if the issue is ceiling leaks.\n8. Roof drainage channels must be cleared of debris.\n9. The full structural repair plan will be shared with administration for budget approval.\n10. Post-repair inspection by the engineer is mandatory before the area is reopened.' },
      { title: 'Blocked/Overflowing Gutters and Drains (External)', steps: '1. Report to the helpdesk with the location (block, side of building).\n2. Blocked gutters cause ceiling leaks and wall moisture damage — treat with urgency.\n3. During monsoon season, this becomes a critical priority.\n4. Maintenance staff will clear leaves, debris, and accumulated dirt from gutters.\n5. Drain outlets on the ground (storm drains) will also be cleared.\n6. Check for structural damage to the gutter/drain piping.\n7. Damaged gutter sections will be replaced with standard PVC or metal channels.\n8. Brackets holding gutters in place will be checked and reinforced.\n9. Establish a pre-monsoon gutter cleaning schedule every year.\n10. Downpipe outlets should direct water away from building foundations.' },
      { title: 'Building Exterior Paint Peeling / Damaged', steps: '1. Report to the helpdesk and the estate/infrastructure team.\n2. Assessment will confirm if it is cosmetic deterioration or surface moisture issue.\n3. Any structural concern alongside the paint damage will be prioritized.\n4. The affected surface will be cleaned, scraped of loose paint, and primed.\n5. Water-resistant exterior grade paint will be applied.\n6. Dark stains (mossy/fungal) will be treated with anti-fungal wash before repainting.\n7. Scaffolding or aerial work platforms will be used for heights — no unsafe ladder work.\n8. Building repainting is typically scheduled annually or biannually.\n9. Post-painting inspection confirms coverage quality.\n10. Campus aesthetic improvements should be bundled with maintenance cycles.' },
      { title: 'Signage / Noticeboard Damaged or Missing', steps: '1. Report to the helpdesk with the location and type of signage (classroom number, directional, emergency exit).\n2. Missing emergency exit signs are a SAFETY issue — treat as HIGH priority.\n3. The maintenance team will fabricate or procure a replacement sign.\n4. Signage must comply with campus standard fonts, sizes, and materials.\n5. Emergency safety signs (exit, first aid, fire extinguisher) must be illuminated or retro-reflective.\n6. Outdoor signage must be made from weather-resistant materials.\n7. Noticeboard glass frames and cork/magnetic boards will be repaired or replaced.\n8. Signs at road/traffic areas must be clearly visible and unobstructed.\n9. All signs are to be mounted at standard heights for visibility.\n10. A campus signage audit should be conducted annually.' },
      { title: 'Flooding / Waterlogging in Campus Area', steps: '1. Immediately alert campus security and administration.\n2. Do not walk through flooded electrical areas.\n3. Switch off ground floor electrical connections if water enters the building.\n4. Report to the helpdesk with the affected blocks and depth of water if known.\n5. Redirect foot and vehicle traffic away from flooded zones.\n6. The maintenance team will activate pumps to remove water.\n7. Check and clear all storm drains in the flooded area.\n8. Sandbagging of key access points may be done during heavy rain.\n9. Long-term assessment of campus drainage network needed if flooding recurs.\n10. Post-flooding, check all ground floor electrical installations before restoring power.' },
      { title: 'HVAC System Not Working Properly', steps: '1. Check if the thermostat is set correctly and batteries are working.\n2. Verify that air vents and return ducts are not blocked or closed.\n3. Check if the air filter needs replacement (should be changed monthly).\n4. Ensure the outdoor unit is clear of debris, leaves, and obstructions.\n5. Report unusual noises, odors, or poor airflow to maintenance.\n6. Check circuit breakers to ensure HVAC system has power.\n7. Allow HVAC technician to inspect refrigerant levels and components.\n8. Schedule regular preventive maintenance to avoid breakdowns.\n9. Document temperature readings and system performance issues.\n10. Consider energy efficiency upgrades during major repairs.' },
      { title: 'Elevator/Lift Malfunction', steps: '1. Do not attempt to force elevator doors open or climb out.\n2. Use emergency call button to contact building security.\n3. Report elevator issues to maintenance and post out-of-order signs.\n4. Ensure alternate access routes are available for accessibility needs.\n5. Check if elevator is getting proper electrical power supply.\n6. Call certified elevator technician for mechanical problems.\n7. Test emergency lighting and communication systems monthly.\n8. Keep elevator maintenance logs and inspection certificates current.\n9. Schedule regular safety inspections as required by local codes.\n10. Train building staff on proper elevator emergency procedures.' },
      { title: 'Campus Lighting Issues (Outdoor)', steps: '1. Report dark areas that pose safety risks to pedestrians.\n2. Check if street lights have power and bulbs are functioning.\n3. Clear vegetation that blocks light fixtures or creates shadows.\n4. Replace burnt-out bulbs promptly to maintain security lighting.\n5. Install additional lighting in areas with frequent foot traffic.\n6. Use energy-efficient LED fixtures for new installations.\n7. Implement timer or sensor controls to reduce energy costs.\n8. Schedule regular inspection and cleaning of all light fixtures.\n9. Coordinate with security team to identify poorly lit areas.\n10. Consider emergency lighting for power outage situations.' },
      { title: 'Campus Landscaping and Grounds Issues', steps: '1. Report overgrown vegetation that blocks walkways or signs.\n2. Clear debris from campus pathways and gathering areas.\n3. Maintain proper drainage around buildings to prevent water damage.\n4. Trim trees and shrubs away from building structures.\n5. Report irrigation system leaks or broken sprinkler heads.\n6. Control weeds and maintain grass areas in good condition.\n7. Apply appropriate fertilizers and pesticides safely.\n8. Remove dead or diseased trees that pose safety hazards.\n9. Install and maintain appropriate seasonal plantings.\n10. Coordinate landscaping work to minimize disruption to campus activities.' },
      { title: 'Building Access Control Problems', steps: '1. Verify that door locks and access card readers are functioning.\n2. Report doors that fail to lock properly or remain unsecured.\n3. Test emergency exit hardware to ensure proper operation.\n4. Check that access cards are programmed with correct permissions.\n5. Maintain master key systems and track key distribution.\n6. Install and maintain proper lighting at all building entrances.\n7. Ensure backup power for electronic access control systems.\n8. Regular maintenance of door closers and hinges.\n9. Update access control systems when staff changes occur.\n10. Coordinate with security team on access control policies.' },
    ],
  },
  {
    name: 'Classroom Equipment',
    solutions: [
      { title: 'Projector Not Working', steps: '1. Check if the projector is plugged into power and the power indicator light is on.\n2. Press the power button — some projectors take 20-30 seconds to warm up.\n3. Check the HDMI/VGA cable connection between the projector and the laptop/PC.\n4. Switch the projector input source (HDMI 1, VGA, etc.) to match the connected source.\n5. On the laptop, press Windows key + P and select "Duplicate" or "Extend".\n6. Check if the projector lamp warning light is on — the bulb may need replacement.\n7. If there is an image but no sound, check the audio output settings on the laptop.\n8. Clean the projector air filter if it shows an overheating warning.\n9. Report to the helpdesk with the classroom number and projector model.\n10. The IT team will carry out on-site diagnosis and arrange lamp/part replacement.' },
      { title: 'Smart Board / Interactive Board Not Responding', steps: '1. Check that the smart board is powered on (look for the power LED).\n2. Ensure the USB cable connecting the board to the PC is firmly plugged in.\n3. Restart the smart board software (SMART Notebook, Promethean) on the PC.\n4. Calibrate the touch surface using the board\'s built-in calibration tool.\n5. Check if the PC recognizes the smart board in Device Manager.\n6. Reinstall the smart board driver software if it is not recognized.\n7. Check for software updates for the smart board driver.\n8. If the board surface is physically damaged (pen tray missing, glass cracked), report for replacement.\n9. Ensure no bright sunlight hits the board directly — this can interfere with touch sensing.\n10. Report the issue to the helpdesk with the classroom and board model.' },
      { title: 'Classroom Speaker / Audio System Not Working', steps: '1. Check if the speaker/amplifier is powered on and the volume is not muted.\n2. Confirm the audio cable is connected from the source (PC/microphone) to the speaker.\n3. On the PC, check that the correct audio output device is selected (Control Panel → Sound).\n4. Test with a different audio source (phone with aux cable) to isolate the problem.\n5. Check for physical damage to the speaker grille or cable connections.\n6. Ensure Bluetooth is paired correctly if it is a wireless system.\n7. Check for ground hum — this may need an audio isolator or ground fix.\n8. For PA (public address) systems, check the amplifier and zone selector settings.\n9. Report to the helpdesk with the classroom number and a description of the audio fault.\n10. The AV technician will inspect and repair or arrange replacement of the faulty component.' },
      { title: 'Lab Equipment Malfunction', steps: '1. Stop the experiment or activity immediately if the equipment fails unexpectedly.\n2. Note any error codes, unusual smells, or sounds from the equipment.\n3. Switch off and unplug the equipment from the power source.\n4. Do not attempt to open or disassemble laboratory equipment yourself.\n5. Inform the lab incharge/supervisor immediately.\n6. Report to the helpdesk with equipment name, lab number, and the nature of the fault.\n7. The lab technician will assess if it is a user error, consumable wear, or hardware failure.\n8. The IT/AV team will be called for digital/electronic lab instruments.\n9. Vendor support will be contacted for equipment under warranty or AMC.\n10. Alternate lab equipment or a rescheduled lab session will be arranged if the fault cannot be fixed the same day.' },
      { title: 'Classroom Computer / Desktop Not Starting', steps: '1. Check if the power cable is plugged in and the power strip is switched on.\n2. Press the power button firmly.\n3. Check if the monitor is on and displaying anything.\n4. If fans spin but no display, reseat the RAM modules.\n5. Check if the BIOS screen appears — if yes, it may be a Windows boot issue.\n6. Try booting into Safe Mode to diagnose software issues.\n7. Run a startup repair from the Windows recovery environment.\n8. Check SMART data from the hard drive — disk failure is a common cause.\n9. Report to the helpdesk with the computer tag number and classroom.\n10. The IT team will perform on-site diagnosis and repair or arrange a replacement desktop.' },
      { title: 'In-Classroom Air Conditioner Not Working', steps: '1. Check if the AC unit is powered on from the wall switch and the remote.\n2. Check the AC remote battery — replace if dead.\n3. Ensure the thermostat is set to a temperature lower than room temperature (cooling mode).\n4. Check if the AC fan is running but no cooling — the compressor may be faulty.\n5. Look for ice formation on the indoor unit — this indicates low refrigerant.\n6. Check and clean the AC air filter if it is blocked with dust.\n7. Check if the AC is in "Fan only" mode instead of "Cool" mode.\n8. Report to the helpdesk with the classroom number and AC unit details.\n9. The HVAC technician will check refrigerant levels, compressor, and thermostat.\n10. Until repaired, arrange portable fans if available to manage room temperature.' },
      { title: 'Document Camera / Visualizer Not Working', steps: '1. Check if the document camera is powered on.\n2. Ensure the USB or HDMI cable is connected to the laptop or projector.\n3. On the PC, open the document camera software (e.g., IPEVO Presenter).\n4. Select the correct input source on the projector to display the camera feed.\n5. Adjust the focus ring on the camera if the image is blurry.\n6. Check if the camera LED light is active — it should illuminate the document.\n7. Try the camera on another PC to rule out a software issue.\n8. Reinstall or update the document camera driver.\n9. Report to the helpdesk with classroom number and camera model.\n10. The IT/AV team will carry out on-site inspection and repair or replacement.' },
      { title: 'Classroom Clock Not Working', steps: '1. Check if the clock battery is dead — replace with a fresh battery (AA/AAA/C type).\n2. Reset the time after replacing the battery.\n3. If it is a networked/digital clock, check for power and network connection.\n4. Report to the helpdesk if the battery replacement does not resolve the issue.\n5. For network-synchronized clocks, the IT team will check the time server configuration.\n6. If the clock face/screen is cracked, it needs physical replacement.\n7. Wall-mounted clocks must be re-mounted safely after battery/mechanism replacement.\n8. Procure a replacement clock of the same size and type if beyond repair.\n9. Place a temporary clock (travel clock) in the classroom until repaired.\n10. Close the ticket after confirming the clock is keeping correct and accurate time.' },
      { title: 'Classroom Lights Not Providing Enough Illumination', steps: '1. Check if all lights in the room are switched on.\n2. Report if several bulbs/tubes have fused — batch replacement may be needed.\n3. Clean dusty light fittings — dust significantly reduces light output.\n4. Report to the helpdesk with room number and number of lights affected.\n5. The electrician will replace fused bulbs/fluorescent tubes.\n6. LED tube upgrades can significantly improve illumination — suggest as an improvement.\n7. Check if the dimmer switch is set too low (if applicable).\n8. Check for loose connections in the light fitting (flickering indicates this).\n9. If only one side of the room is affected, the circuit wiring for that section should be checked.\n10. Post-repair, measure lux levels if smart lighting tools are available to confirm adequacy.' },
      { title: 'Microphone Not Working During Lecture', steps: '1. Check if the microphone is switched on (mute button should be off).\n2. Check the battery on wireless/handheld microphones.\n3. Ensure the microphone receiver (for wireless) is powered on and paired.\n4. For wired microphones, check the XLR or 3.5mm connection to the amplifier.\n5. Increase the microphone gain/level on the amplifier or mixer.\n6. Test the mic on a different audio source or amplifier.\n7. Check for interference causing noise in wireless microphones (try a different channel).\n8. Tap the microphone gently — no sound confirms it may be internally faulty.\n9. Report to the helpdesk with classroom number and microphone type.\n10. A spare microphone should be available in the AV equipment store for emergency loan.' },
      { title: 'Smart TV/Display Monitor Issues', steps: '1. Check if the TV/monitor power LED is on and device is receiving power.\n2. Try different input sources (HDMI1, HDMI2, VGA) using remote control.\n3. Check all cable connections between source device and display.\n4. Test with a different source device to isolate the problem.\n5. Check if screen brightness is turned down too low.\n6. Power cycle both the display and source device.\n7. Check for software updates for smart TV operating system.\n8. Report dead pixels, color distortion, or physical screen damage immediately.\n9. Report to helpdesk with classroom number and display model information.\n10. Ensure remote control batteries are functional and paired properly.' },
      { title: 'Laboratory Computers Slow Performance', steps: '1. Check available hard disk space - less than 10% free causes slowdowns.\n2. Close unnecessary programs and browser tabs consuming memory.\n3. Run disk cleanup utility to remove temporary files.\n4. Check Task Manager for high CPU/memory usage processes.\n5. Restart the computer to clear memory and refresh system.\n6. Run antivirus scan to check for malware affecting performance.\n7. Check Windows Update for pending system updates.\n8. Report consistently slow performance to IT support team.\n9. Consider hardware upgrades if software is resource-intensive.\n10. Schedule regular maintenance and optimize system performance settings.' },
      { title: 'Classroom WiFi Connectivity Problems', steps: '1. Check if device WiFi is enabled and not in airplane mode.\n2. Forget and reconnect to the campus WiFi network.\n3. Verify correct network credentials are being used.\n4. Test connectivity with different devices in same location.\n5. Move closer to wireless access point to test signal strength.\n6. Check if specific websites or services are blocked.\n7. Try switching between 2.4GHz and 5GHz network bands.\n8. Report persistent connectivity issues with location details.\n9. IT team will check access point status and configuration.\n10. Use ethernet connection as backup while WiFi is being repaired.' },
      { title: 'Video Conference Equipment Setup', steps: '1. Test camera, microphone, and speakers before important meetings.\n2. Check internet bandwidth requirements for video conferencing.\n3. Position camera at eye level and ensure proper lighting.\n4. Test screen sharing functionality with presentation materials.\n5. Verify audio levels and eliminate echo or feedback.\n6. Have backup communication method ready in case of technical issues.\n7. Update video conferencing software to latest version.\n8. Report equipment malfunctions to IT support immediately.\n9. Train users on basic troubleshooting and operation procedures.\n10. Maintain equipment inventory and replacement parts for quick repairs.' },
      { title: 'Digital Signage Display Issues', steps: '1. Check power connection and ensure display is receiving electricity.\n2. Verify network connection for content management system.\n3. Check if content is scheduled correctly in management software.\n4. Test display with different input sources to isolate issues.\n5. Check for software updates on digital signage media player.\n6. Verify content format compatibility (image/video resolution).\n7. Report display hardware issues like dead pixels or color problems.\n8. Check mounting hardware for security and proper positioning.\n9. Coordinate content updates and scheduling with communications team.\n10. Maintain backup display units for critical campus information areas.' },
    ],
  },
]
